import type { Card, Category, Frequency, DifficultyLevel } from '../types';

const NOW = new Date();

function card(
  id: string,
  category: Category,
  titleEn: string,
  titleHe: string,
  descEn: string,
  descHe: string,
  frequency: Frequency,
  timeEstimate: number,
  difficulty: DifficultyLevel = 1,
): Card {
  return {
    id,
    category,
    title: { en: titleEn, he: titleHe },
    description: { en: descEn, he: descHe },
    details: { en: '', he: '' },
    holder: null,
    status: 'unassigned',
    metadata: {
      createdAt: NOW,
      modifiedAt: NOW,
      isCustom: false,
      isActive: true,
      tags: [],
      difficulty,
      frequency,
      timeEstimate,
    },
    history: [],
  };
}

